import { useState, useMemo, useEffect, useCallback } from 'react'
import { Link, useSearchParams } from 'react-router-dom'
import { HiOutlineEye, HiOutlinePencil, HiOutlineArchive } from 'react-icons/hi'
import Swal from 'sweetalert2'
import FormActions from '../../components/FormActions'
import StatusBadge from '../../components/StatusBadge'
import PageHeader from '../../components/PageHeader'
import DataTable from '../../components/DataTable'
import {
  fetchDeals,
  fetchActiveClientsForDeals,
  fetchActivePropertiesForDeals,
  getNextDealId,
  DEAL_STATUS_LABELS,
  getDealPaymentsSummary,
  type Deal,
  type DealStatus,
  type DealPaymentEntry,
  type DealStatusHistoryEntry,
  updateDealTransaction,
  createDealTransaction,
  deleteDealFromApi,
  deleteDealFromLocal,
} from '../../services/dealsService'
import {
  fetchInquiries,
  saveInquiryStore,
  updateInquiryInApi,
  type InquiryRecord,
} from '../../services/inquiriesService'
import './admin-common.css'
import './Deals.css'

const DEAL_STATUSES: DealStatus[] = [
  'Inquiry',
  'Negotiation',
  'Reserved',
  'Processing Documents',
  'Closed',
  'Cancelled',
]

function formatDisplayDate(iso: string): string {
  const d = new Date(iso)
  const mon = d.toLocaleString('en-US', { month: 'short' })
  const day = d.getDate()
  return `${mon} ${day}`
}

function buildDealSearchHaystack(d: Deal): string {
  const parts: string[] = [
    d.id,
    d.dealId,
    d.clientId,
    d.clientName,
    d.propertyId ?? '',
    d.propertyTitle,
    d.status,
    DEAL_STATUS_LABELS[d.status],
    d.price,
    d.date,
    d.closingDate ?? '',
    d.expectedClosingDate ?? '',
    d.createdAt ?? '',
    d.updatedAt ?? '',
    d.cancelledReason ?? '',
    d.adminNotes ?? '',
    d.paymentMethod ?? '',
    d.propertyPrice ?? '',
    d.finalSalePrice ?? '',
    d.discount ?? '',
    getDealPaymentsSummary(d),
  ]
  const closeOrDate = d.closingDate || d.date
  if (closeOrDate) {
    try {
      parts.push(formatDisplayDate(closeOrDate), new Date(closeOrDate).toLocaleDateString())
    } catch {
      /* ignore */
    }
  }
  if (d.payments?.length) {
    for (const p of d.payments) {
      parts.push(p.amount, p.type, p.date, p.notes ?? '', p.proof ?? '')
    }
  }
  if (d.statusHistory?.length) {
    for (const h of d.statusHistory) {
      parts.push(h.status, h.at, h.note ?? '')
    }
  }
  if (d.activity?.length) {
    for (const a of d.activity) {
      parts.push(a.type, a.date, a.label, a.details ?? '')
    }
  }
  const row = d._row
  if (row?.leadOriginId) parts.push(row.leadOriginId)
  if (row?.payment) parts.push(row.payment)
  if (row?.agent) parts.push(row.agent)
  return parts.filter(Boolean).join(' ').toLowerCase()
}

export default function AdminDeals() {
  const [searchParams, setSearchParams] = useSearchParams()
  const clientIdFromUrl = searchParams.get('clientId') ?? ''
  const [deals, setDeals] = useState<Deal[]>(() => fetchDeals())
  const [showAdd, setShowAdd] = useState(false)
  const [editingDeal, setEditingDeal] = useState<Deal | null>(null)
  const [searchQuery, setSearchQuery] = useState('')
  const [loading, setLoading] = useState(true)
  const [showCancelConfirmModal, setShowCancelConfirmModal] = useState(false)
  const [cancelReason, setCancelReason] = useState('')
  const [cancelReasonError, setCancelReasonError] = useState('')
  const [archiveModalDeal, setArchiveModalDeal] = useState<Deal | null>(null)
  const [archiveReason, setArchiveReason] = useState('')
  const [archiveError, setArchiveError] = useState('')
  const [form, setForm] = useState(() => ({
    clientId: '',
    clientName: '',
    propertyId: '',
    propertyTitle: '',
    leadOriginId: '' as string | null,
    propertyPrice: '',
    finalSalePrice: '',
    paymentMethod: '',
    status: 'Inquiry' as DealStatus,
    createdAt: new Date().toISOString().slice(0, 10),
    closingDate: '',
    expectedClosingDate: '',
    adminNotes: '',
    firstPaymentType: '' as '' | 'reservation' | 'downpayment' | 'full_payment',
    firstPaymentAmount: '',
    firstPaymentDate: '',
  }))

  useEffect(() => {
    setLoading(false)
  }, [])

  const clients = fetchActiveClientsForDeals()
  const properties = fetchActivePropertiesForDeals()

  useEffect(() => {
    const shouldOpenCreate = searchParams.get('createDeal') === '1'
    if (!shouldOpenCreate || !clientIdFromUrl) return

    const propertyIdFromUrl = searchParams.get('propertyId') ?? ''
    const propertyTitleFromUrl = searchParams.get('propertyTitle') ?? ''
    const clientNameFromUrl = searchParams.get('clientName') ?? ''
    const leadOriginIdFromUrl = searchParams.get('leadOriginId')
    const propsList = fetchActivePropertiesForDeals()
    const prop = propertyIdFromUrl ? propsList.find((p) => p.id === propertyIdFromUrl) : undefined
    const listPrice = prop?.price ?? ''
    setShowAdd(true)
    setEditingDeal(null)
    setForm((prev) => ({
      ...prev,
      clientId: clientIdFromUrl,
      clientName: clientNameFromUrl,
      propertyId: propertyIdFromUrl,
      propertyTitle: propertyTitleFromUrl || prop?.title || '',
      leadOriginId: leadOriginIdFromUrl,
      propertyPrice: listPrice || prev.propertyPrice,
      finalSalePrice: listPrice || prev.finalSalePrice,
    }))
  }, [searchParams, clientIdFromUrl])
  const clientFromUrl = clientIdFromUrl ? clients.find((c) => c.id === clientIdFromUrl) : null

  const filtered = useMemo(() => {
    let list = [...deals]

    if (clientIdFromUrl) {
      list = list.filter((d) => d.clientId === clientIdFromUrl)
    }

    if (searchQuery.trim()) {
      const q = searchQuery.trim().toLowerCase()
      list = list.filter((d) => buildDealSearchHaystack(d).includes(q))
    }

    const dealTime = (d: (typeof list)[number]) =>
      new Date(d.createdAt || d.closingDate || d.date || 0).getTime()
    return [...list].sort((a, b) => dealTime(b) - dealTime(a))
  }, [deals, clientIdFromUrl, searchQuery])

  const refreshDeals = () => setDeals(fetchDeals())

  const openEdit = (d: Deal) => {
    setForm({
      clientId: d.clientId,
      clientName: d.clientName,
      propertyId: d.propertyId ?? '',
      propertyTitle: d.propertyTitle,
      leadOriginId: d._row.leadOriginId ?? null,
      propertyPrice: d.propertyPrice ?? '',
      finalSalePrice: d.finalSalePrice ?? d.price ?? '',
      paymentMethod: d.paymentMethod ?? '',
      status: d.status,
      createdAt: d.createdAt?.slice(0, 10) ?? d.date?.slice(0, 10) ?? new Date().toISOString().slice(0, 10),
      closingDate: d.closingDate ?? '',
      expectedClosingDate: d.expectedClosingDate ?? '',
      adminNotes: d.adminNotes ?? '',
      firstPaymentType: '' as '' | 'reservation' | 'downpayment' | 'full_payment',
      firstPaymentAmount: '',
      firstPaymentDate: '',
    })
    setEditingDeal(d)
  }

  const closeSidebar = () => {
    setShowAdd(false)
    setEditingDeal(null)
  }

  const extractNumericAmount = (value: string): string => {
    const numeric = String(value ?? '').replace(/[^\d.]/g, '')
    return numeric
  }

  const handleAddDeal = useCallback(async () => {
    if (!form.clientId) {
      window.alert('Client is required before creating a deal.')
      return
    }
    if (!form.propertyTitle.trim()) return
    if (form.status === 'Closed' && !form.closingDate.trim()) {
      window.alert('Closing date is required when closing a deal.')
      return
    }
    const prop = properties.find((p) => p.id === form.propertyId)
    const propertyTitle = (form.propertyTitle.trim() || prop?.title) ?? ''
    if (!propertyTitle) return
    const amount = form.finalSalePrice.trim() || form.propertyPrice.trim() || 'Γé▒0'
    const createdAt = form.createdAt || new Date().toISOString().slice(0, 10)
    const payments: DealPaymentEntry[] = []
    if (form.firstPaymentType && form.firstPaymentAmount.trim()) {
      payments.push({
        type: form.firstPaymentType,
        amount: form.firstPaymentAmount.trim(),
        date: form.firstPaymentDate || createdAt,
      })
    }
    const statusHistory: DealStatusHistoryEntry[] = [
      { status: form.status, at: createdAt, note: 'Deal created' },
    ]
    const dealId = getNextDealId()
    const clientLeadOriginId =
      form.leadOriginId ?? clients.find((c) => c.id === form.clientId)?.leadOriginId ?? null
    createDealTransaction(form.clientId, {
      id: 't' + Date.now(),
      dealId,
      propertyTitle,
      propertyId: form.propertyId || undefined,
      amount,
      date: form.closingDate || createdAt,
      status: form.status,
      propertyPrice: form.propertyPrice.trim() || undefined,
      finalSalePrice: form.finalSalePrice.trim() || undefined,
      paymentMethod: form.paymentMethod.trim() || undefined,
      createdAt,
      closingDate: form.closingDate.trim() || undefined,
      expectedClosingDate: form.expectedClosingDate.trim() || undefined,
      updatedAt: createdAt,
      adminNotes: form.adminNotes.trim() || undefined,
      payments: payments.length ? payments : undefined,
      statusHistory,
      documents: {
        reservationForm: { status: 'pending' },
        contract: { status: 'pending' },
        receipt: { status: 'pending' },
      },
      leadOriginId: clientLeadOriginId,
    } as Parameters<typeof createDealTransaction>[1])

    if (clientLeadOriginId) {
      const originInquiry = fetchInquiries().find((row) => row.id === clientLeadOriginId)
      if (originInquiry) {
        const convertedInquiry: InquiryRecord = {
          ...originInquiry,
          status: 'converted',
          linkedClientId: form.clientId,
        }
        saveInquiryStore((prev) =>
          prev.map((row) => (row.id === clientLeadOriginId ? convertedInquiry : row))
        )
        try {
          await updateInquiryInApi(convertedInquiry)
        } catch {
          /* deal is already created locally; inquiry DB sync can retry later */
        }
      }
    }

    setForm({
      clientId: '',
      clientName: '',
      propertyId: '',
      propertyTitle: '',
      leadOriginId: null,
      propertyPrice: '',
      finalSalePrice: '',
      paymentMethod: '',
      status: 'Inquiry',
      createdAt: new Date().toISOString().slice(0, 10),
      closingDate: '',
      expectedClosingDate: '',
      adminNotes: '',
      firstPaymentType: '',
      firstPaymentAmount: '',
      firstPaymentDate: '',
    })
    setShowAdd(false)
    refreshDeals()
  }, [clients, form, properties])

  const handleUpdateDeal = () => {
    if (!editingDeal) return
    if (form.status === 'Closed' && !form.closingDate.trim()) {
      window.alert('Closing date is required when closing a deal.')
      return
    }
    if (form.status === 'Cancelled') {
      setShowCancelConfirmModal(true)
      setCancelReason('')
      setCancelReasonError('')
      return
    }
    applyDealUpdate()
  }

  const handleArchiveDeal = (d: Deal) => {
    setArchiveModalDeal(d)
    setArchiveReason('')
    setArchiveError('')
  }

  const confirmArchiveDeal = async () => {
    if (!archiveModalDeal) return
    const reason = archiveReason.trim()
    if (!reason) {
      setArchiveError('Please provide a reason for archiving.')
      return
    }

    try {
      await deleteDealFromApi(archiveModalDeal.id)
      deleteDealFromLocal(archiveModalDeal._clientId, archiveModalDeal.id)
      setDeals(prev => prev.filter(x => x.id !== archiveModalDeal.id))
      
      Swal.fire({
        icon: 'success',
        title: 'Deal archived',
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 2000,
        timerProgressBar: true,
      })
      setArchiveModalDeal(null)
      setArchiveReason('')
      setArchiveError('')
    } catch (err) {
      Swal.fire({
        icon: 'error',
        title: 'Archive failed',
        text: err instanceof Error ? err.message : 'Could not archive deal.',
      })
    }
  }

  const confirmCancelDeal = () => {
    if (!editingDeal) return
    const reason = cancelReason.trim() || null
    applyDealUpdate(reason)
    setShowCancelConfirmModal(false)
    setCancelReason('')
    setCancelReasonError('')
    closeSidebar()
    refreshDeals()
    setTimeout(() => {
      Swal.fire({
        icon: 'success',
        title: 'Deal cancelled',
        ...(reason && { text: `Reason: ${reason}` }),
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 3000,
        timerProgressBar: true,
      })
    }, 100)
  }

  const applyDealUpdate = (cancelledReason: string | null = null) => {
    if (!editingDeal) return
    const amount = form.finalSalePrice.trim() || form.propertyPrice.trim() || editingDeal._row.amount
    const updatedAt = new Date().toISOString().slice(0, 10)
    const payload: Record<string, unknown> = {
      propertyTitle: form.propertyTitle.trim() || editingDeal.propertyTitle,
      propertyId: form.propertyId || undefined,
      amount,
      propertyPrice: form.propertyPrice.trim() || undefined,
      finalSalePrice: form.finalSalePrice.trim() || undefined,
      paymentMethod: form.paymentMethod.trim() || undefined,
      status: form.status,
      createdAt: form.createdAt || undefined,
      closingDate: form.closingDate.trim() || undefined,
      expectedClosingDate: form.expectedClosingDate.trim() || undefined,
      adminNotes: form.adminNotes.trim() || undefined,
      updatedAt,
    }
    if (form.status === 'Cancelled' && cancelledReason !== undefined) {
      payload.cancelledReason = cancelledReason
    }
    updateDealTransaction(editingDeal._clientId, editingDeal.id, payload)
    if (form.status !== 'Cancelled') {
      closeSidebar()
      refreshDeals()
      setTimeout(() => {
        Swal.fire({
          icon: 'success',
          title: 'Deal updated',
          toast: true,
          position: 'top-end',
          showConfirmButton: false,
          timer: 3000,
          timerProgressBar: true,
        })
      }, 100)
    }
  }

  const displayDate = (d: Deal) => formatDisplayDate(d.closingDate || d.date)

  return (
    <div className="admin-deals">
      <PageHeader
        title="Deals"
        subtitle="Transaction engine. Who bought what, when, and at what stage in the pipeline."
        toolbar={
          <>
            {clientFromUrl && (
              <span className="admin-deals-client-filter">
                Showing deals for <strong>{clientFromUrl.name}</strong>
                <button
                  type="button"
                  className="btn btn-outline btn-sm"
                  onClick={() => setSearchParams({})}
                  style={{ marginLeft: 8 }}
                >
                  Show all
                </button>
              </span>
            )}
            <input
              type="search"
              className="admin-input admin-deals-search"
              placeholder="Search deal ID, client, property, status, price, dates, payments, notesΓÇª"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              aria-label="Search all deal fields"
            />
            <button type="button" className="btn btn-primary" onClick={() => setShowAdd(true)}>
              Add Deal
            </button>
          </>
        }
      />
      <DataTable wrapperClassName="admin-deals-table-wrap" tableClassName="deals-table">
        <thead>
          <tr>
            <th className="th-plain">
              <span className="th-label">Deal ID</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Client</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Property</span>
            </th>
            <th className="th-plain col-status">
              <span className="th-label">Status</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Price</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Discount</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Payments</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Closing Date</span>
            </th>
            <th className="col-actions">Actions</th>
          </tr>
        </thead>
        <tbody>
          {loading ? (
            <tr>
              <td colSpan={9} className="admin-empty-cell">
                Loading deals...
              </td>
            </tr>
          ) : filtered.length === 0 ? (
            <tr>
              <td colSpan={9} className="admin-empty-cell">
                No deals found.
              </td>
            </tr>
          ) : (
            filtered.map((d) => (
              <tr key={d.clientId + d.id}>
                <td className="deals-deal-id">{d.dealId}</td>
                <td>
                  <Link to={`/admin/clients/${d.clientId}`}>{d.clientName}</Link>
                </td>
                <td>
                  {d.propertyId ? (
                    <Link to={`/admin/properties/${d.propertyId}`}>{d.propertyTitle}</Link>
                  ) : (
                    d.propertyTitle
                  )}
                </td>
                <td>
                  <StatusBadge className={`admin-badge admin-badge--deal-${d.status.toLowerCase().replace(/\s+/g, '-')}`}>
                    {DEAL_STATUS_LABELS[d.status]}
                  </StatusBadge>
                </td>
                <td className="deals-amount">{d.price}</td>
                <td className="deals-discount">{d.discount ?? 'ΓÇö'}</td>
                <td className="deals-payments">{getDealPaymentsSummary(d)}</td>
                <td>{displayDate(d)}</td>
                <td className="col-actions">
                  <Link
                    to={`/admin/deals/${d.dealId}`}
                    className="btn-icon-btn"
                    data-tooltip="View deal ΓÇö open the full deal page (timeline, payments, documents)."
                    title="View deal ΓÇö full page with timeline and documents"
                    aria-label="View deal details"
                  >
                    <HiOutlineEye />
                  </Link>
                  <button
                    type="button"
                    className="btn-icon-btn"
                    data-tooltip="Edit deal ΓÇö change stage, price, dates, payments, and notes in the side panel."
                    title="Edit deal ΓÇö pipeline, pricing, and payments"
                    aria-label="Edit this deal"
                    onClick={() => openEdit(d)}
                  >
                    <HiOutlinePencil />
                  </button>
                  <button
                    type="button"
                    className="btn-icon-btn btn-icon-btn--danger"
                    data-tooltip="Archive deal ΓÇö hides this deal and moves it to the Archives hub (soft delete)."
                    title="Archive deal"
                    aria-label="Archive this deal"
                    onClick={() => handleArchiveDeal(d)}
                  >
                    <HiOutlineArchive />
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </DataTable>

      {/* Add / Edit Deal sidebar */}
      {(showAdd || editingDeal) && (
        <div className="deal-sidebar-overlay" onClick={closeSidebar} role="presentation">
          <div className="deal-sidebar" onClick={(e) => e.stopPropagation()} role="dialog" aria-label={editingDeal ? 'Edit Deal' : 'Add Deal'}>
            <div className="deal-sidebar-header">
              <h2>{editingDeal ? 'Edit Deal' : 'Add Deal'}</h2>
              <button type="button" className="deal-sidebar-close" onClick={closeSidebar} aria-label="Close">├ù</button>
            </div>
            <div className="deal-sidebar-body">
              <div className="admin-form-row">
                <label>Client *</label>
                <select
                  value={form.clientId}
                  onChange={(e) => {
                    const nextClientId = e.target.value
                    const selectedClient = clients.find((c) => c.id === nextClientId)
                    setForm((f) => ({
                      ...f,
                      clientId: nextClientId,
                      clientName: selectedClient?.name ?? '',
                      leadOriginId: selectedClient?.leadOriginId ?? null,
                    }))
                  }}
                  className="admin-input"
                  disabled={!!editingDeal}
                >
                  <option value="">Select client</option>
                  {clients.map((c) => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
              </div>
              <div className="admin-form-row">
                <label>Property *</label>
                <select
                  value={form.propertyId}
                  onChange={(e) => {
                    const p = properties.find((x) => x.id === e.target.value)
                    setForm((f) => {
                      const nextPropertyPrice = p?.price ?? ''
                      const shouldAutofillFullPayment = f.firstPaymentType === 'full_payment'
                      return {
                        ...f,
                        propertyId: e.target.value,
                        propertyTitle: p?.title ?? '',
                        propertyPrice: nextPropertyPrice,
                        firstPaymentAmount: shouldAutofillFullPayment
                          ? extractNumericAmount(nextPropertyPrice)
                          : f.firstPaymentAmount,
                      }
                    })
                  }}
                  className="admin-input"
                >
                  <option value="">Select property</option>
                  {properties.map((p) => (
                    <option key={p.id} value={p.id}>{p.title} ΓÇö {p.price}</option>
                  ))}
                </select>
              </div>
              <div className="admin-form-row">
                <label>Deal Status</label>
                <select
                  value={form.status}
                  onChange={(e) => setForm((f) => ({ ...f, status: e.target.value as DealStatus }))}
                  className="admin-input"
                >
                  {DEAL_STATUSES.map((s) => (
                    <option key={s} value={s}>{DEAL_STATUS_LABELS[s]}</option>
                  ))}
                </select>
              </div>
              <div className="admin-form-row">
                <label>Property Price</label>
                <input
                  value={form.propertyPrice}
                  onChange={(e) => setForm((f) => ({ ...f, propertyPrice: e.target.value }))}
                  placeholder="Γé▒0"
                  className="admin-input"
                />
              </div>
              <div className="admin-form-row">
                <label>Final Sale Price (optional)</label>
                <input
                  value={form.finalSalePrice}
                  onChange={(e) => setForm((f) => ({ ...f, finalSalePrice: e.target.value }))}
                  placeholder="Γé▒0"
                  className="admin-input"
                />
              </div>
              {!editingDeal && (
                <div className="admin-form-row">
                  <label>First payment (optional)</label>
                  <div className="deal-sidebar-payment-row">
                    <select
                      value={form.firstPaymentType}
                      onChange={(e) =>
                        setForm((f) => {
                          const nextType = e.target.value as typeof form.firstPaymentType
                          const shouldAutofill = nextType === 'full_payment'
                          return {
                            ...f,
                            firstPaymentType: nextType,
                            firstPaymentAmount: shouldAutofill
                              ? extractNumericAmount(f.propertyPrice)
                              : f.firstPaymentAmount,
                          }
                        })
                      }
                      className="admin-input"
                    >
                      <option value="">ΓÇö</option>
                      <option value="reservation">Reservation</option>
                      <option value="downpayment">Downpayment</option>
                      <option value="full_payment">Full payment</option>
                    </select>
                    <input
                      value={form.firstPaymentAmount}
                      onChange={(e) => setForm((f) => ({ ...f, firstPaymentAmount: e.target.value }))}
                      placeholder="Amount"
                      className="admin-input"
                    />
                    <input
                      type="date"
                      value={form.firstPaymentDate}
                      onChange={(e) => setForm((f) => ({ ...f, firstPaymentDate: e.target.value }))}
                      className="admin-input"
                    />
                  </div>
                </div>
              )}
              <div className="admin-form-row">
                <label>Payment Method</label>
                <input
                  value={form.paymentMethod}
                  onChange={(e) => setForm((f) => ({ ...f, paymentMethod: e.target.value }))}
                  placeholder="e.g. Cash, Bank Transfer"
                  className="admin-input"
                />
              </div>
              <div className="admin-form-row">
                <label>Deal Created Date</label>
                <input
                  type="date"
                  value={form.createdAt}
                  onChange={(e) => setForm((f) => ({ ...f, createdAt: e.target.value }))}
                  className="admin-input"
                />
              </div>
              <div className="admin-form-row">
                <label>Expected closing date</label>
                <input
                  type="date"
                  value={form.expectedClosingDate}
                  onChange={(e) => setForm((f) => ({ ...f, expectedClosingDate: e.target.value }))}
                  className="admin-input"
                />
                <span className="deal-form-hint">Optional</span>
              </div>
              <div className="admin-form-row">
                <label>Closing date (actual)</label>
                <input
                  type="date"
                  value={form.closingDate}
                  onChange={(e) => setForm((f) => ({ ...f, closingDate: e.target.value }))}
                  className="admin-input"
                />
              </div>
              <div className="admin-form-row">
                <label>Admin Notes</label>
                <textarea
                  value={form.adminNotes}
                  onChange={(e) => setForm((f) => ({ ...f, adminNotes: e.target.value }))}
                  placeholder="Optional"
                  className="admin-input"
                  rows={3}
                />
              </div>
            </div>
            <FormActions
              primaryLabel={editingDeal ? 'Update Deal' : 'Add Deal'}
              onPrimary={editingDeal ? handleUpdateDeal : handleAddDeal}
              onCancel={closeSidebar}
            />
          </div>
        </div>
      )}

      {/* Confirm cancel deal modal ΓÇö same pattern as property archive */}
      {showCancelConfirmModal && editingDeal && (
        <div
          className="admin-modal-overlay"
          onClick={() => setShowCancelConfirmModal(false)}
          role="dialog"
          aria-modal="true"
          aria-labelledby="cancel-deal-modal-title"
        >
          <div className="admin-modal archive-modal" onClick={(e) => e.stopPropagation()}>
            <div className="admin-modal-header">
              <h2 id="cancel-deal-modal-title">Cancel this deal?</h2>
              <button
                type="button"
                className="admin-modal-close"
                onClick={() => setShowCancelConfirmModal(false)}
                aria-label="Close"
              >
                ├ù
              </button>
            </div>
            <div className="admin-modal-body">
              <div className="archive-warning">
                <p className="archive-warning-title">ΓÜá∩╕Å Confirmation</p>
                <p>
                  You are about to set deal <strong>{editingDeal.dealId}</strong> to <strong>Cancelled</strong>.
                  This will remove it from the active pipeline.
                </p>
              </div>
              <div className="admin-form-row">
                <label htmlFor="cancel-deal-reason">Reason for cancelling (optional)</label>
                <textarea
                  id="cancel-deal-reason"
                  className="admin-input"
                  value={cancelReason}
                  onChange={(e) => {
                    setCancelReason(e.target.value)
                    setCancelReasonError('')
                  }}
                  placeholder="e.g. Client backed out, Financing rejected, Price too high"
                  rows={3}
                />
              </div>
              {cancelReasonError && <p className="form-error">{cancelReasonError}</p>}
              <div className="archive-actions">
                <button type="button" className="btn btn-primary" onClick={confirmCancelDeal}>
                  Cancel deal
                </button>
                <button
                  type="button"
                  className="btn btn-outline"
                  onClick={() => setShowCancelConfirmModal(false)}
                >
                  Back
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
      {/* Archive deal modal ΓÇö same pattern as client archive */}
      {archiveModalDeal && (
        <div
          className="admin-modal-overlay"
          onClick={() => setArchiveModalDeal(null)}
          role="dialog"
          aria-modal="true"
          aria-labelledby="archive-deal-modal-title"
        >
          <div className="admin-modal archive-modal" onClick={(e) => e.stopPropagation()}>
            <div className="admin-modal-header">
              <h2 id="archive-deal-modal-title">Archive deal</h2>
              <button
                type="button"
                className="admin-modal-close"
                onClick={() => setArchiveModalDeal(null)}
                aria-label="Close"
              >
                &times;
              </button>
            </div>
            <div className="admin-modal-body">
              <div className="archive-warning">
                <p className="archive-warning-title">ΓÜá∩╕Å Confirmation</p>
                <p>
                  You are about to archive deal <strong>{archiveModalDeal.dealId}</strong>.
                </p>
              </div>
              <div className="admin-form-row">
                <label htmlFor="archive-reason">Reason for archiving <span className="required">*</span></label>
                <textarea
                  id="archive-reason"
                  className="admin-input"
                  value={archiveReason}
                  onChange={(e) => { setArchiveReason(e.target.value); setArchiveError(''); }}
                  placeholder="e.g. Transaction completed, client withdrew, listing expired"
                  rows={3}
                  required
                />
              </div>
              {archiveError && <p className="form-error">{archiveError}</p>}
              <div className="archive-actions">
                <button type="button" className="btn btn-primary" onClick={confirmArchiveDeal}>
                  Archive deal
                </button>
                <button
                  type="button"
                  className="btn btn-outline"
                  onClick={() => setArchiveModalDeal(null)}
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useMemo, useRef } from 'react'
import { Link, useNavigate, useLocation } from 'react-router-dom'
import Swal from 'sweetalert2'
import { HiOutlinePlus, HiOutlineDocumentDownload, HiOutlineEye, HiOutlinePencil, HiOutlineArchive, HiOutlineChat, HiOutlineChevronUp, HiOutlineChevronDown, HiOutlineMenu, HiOutlineClipboardList, HiOutlinePhone, HiOutlineMail, HiOutlineCalendar, HiOutlineCash, HiOutlineClock } from 'react-icons/hi'
import FormActions from '../../components/FormActions'
import StatusBadge from '../../components/StatusBadge'
import {
  fetchClients,
  saveClientStore,
  getClientStore,
  getStatusLabel,
  getStatusDescription,
  logClientActivity,
  type ClientRecord,
  type ClientStatus,
  type ClientSource,
  type LastActivityType,
} from '../../services/clientsService'
import { persistClientToApi, deleteClientFromApi } from '../../services/clientsApi'
import {
  BULACAN_PROVINCE,
  BULACAN_MUNICIPALITIES,
  formatBulacanAddressLine,
  getBarangaysForMunicipality,
  isValidPhMobile09,
} from '../../data/bulacanAddress'
import { useAdminAuth } from '../../hooks/useAdminAuth'
import './admin-common.css'
import './Clients.css'

const SOURCES: ClientSource[] = ['Facebook', 'Website', 'Referral', 'Walk-in']
const STATUSES: ClientStatus[] = [
  'new',
  'contacted',
  'interested',
  'negotiating',
  'reserved',
  'closed',
  'lost',
  'inactive',
]

type SortCol = 'name' | 'email' | 'phone' | 'dealsCount' | 'lastActivity'

/** Status column filter ΓÇö `pipeline` = contacted | interested | negotiating | reserved */
type ClientStatusFilter = ClientStatus | 'all' | '' | 'pipeline'

const PIPELINE_STATUSES: ClientStatus[] = ['contacted', 'interested', 'negotiating', 'reserved']

export default function AdminClients() {
  const { user } = useAdminAuth()
  const actor = user?.name ?? 'Unknown'
  const navigate = useNavigate()
  const location = useLocation()
  const [clients, setClients] = useState<ClientRecord[]>(() => fetchClients())
  const [loading, setLoading] = useState(true)
  const [sortBy, setSortBy] = useState<SortCol | ''>('')
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc')
  const [statusFilter, setStatusFilter] = useState<ClientStatusFilter>('')
  const [statusDropdownOpen, setStatusDropdownOpen] = useState(false)
  const statusDropdownRef = useRef<HTMLDivElement>(null)
  const [sourceFilter, setSourceFilter] = useState<ClientSource | 'all' | ''>('')
  const [sourceDropdownOpen, setSourceDropdownOpen] = useState(false)
  const sourceDropdownRef = useRef<HTMLDivElement>(null)
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set())
  const [showForm, setShowForm] = useState(false)
  const [editingClient, setEditingClient] = useState<ClientRecord | null>(null)
  const [addMenuOpen, setAddMenuOpen] = useState(false)
  const addMenuRef = useRef<HTMLDivElement>(null)
  const [showBulkUpload, setShowBulkUpload] = useState(false)
  const [archiveModalClient, setArchiveModalClient] = useState<ClientRecord | null>(null)
  const [archiveReason, setArchiveReason] = useState('')
  const [archiveError, setArchiveError] = useState('')
  const [showBulkArchiveModal, setShowBulkArchiveModal] = useState(false)
  const [bulkStatusSelectValue, setBulkStatusSelectValue] = useState('')
  const [bulkArchiveReason, setBulkArchiveReason] = useState('')
  const [bulkArchiveError, setBulkArchiveError] = useState('')

  useEffect(() => {
    setClients(fetchClients())
    setLoading(false)
  }, [])

  useEffect(() => {
    const editId = (location.state as { editId?: string } | null)?.editId
    if (editId) {
      const c = fetchClients().find((x) => x.id === editId)
      if (c) {
        setEditingClient(c)
        setShowForm(true)
      }
      navigate('/admin/clients', { replace: true, state: {} })
    }
  }, [location.state, navigate])

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      const target = e.target as Node
      if (statusDropdownRef.current && !statusDropdownRef.current.contains(target)) setStatusDropdownOpen(false)
      if (sourceDropdownRef.current && !sourceDropdownRef.current.contains(target)) setSourceDropdownOpen(false)
      if (addMenuRef.current && !addMenuRef.current.contains(target)) setAddMenuOpen(false)
    }
    if (statusDropdownOpen || sourceDropdownOpen || addMenuOpen) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [statusDropdownOpen, sourceDropdownOpen, addMenuOpen])

  const filteredByStatus = useMemo(() => {
    const active = clients.filter((c) => !c.archived)
    if (!statusFilter || statusFilter === 'all') return active
    if (statusFilter === 'pipeline') {
      return active.filter((c) => PIPELINE_STATUSES.includes(c.status))
    }
    return active.filter((c) => c.status === statusFilter)
  }, [clients, statusFilter])

  const filteredByStatusAndSource = useMemo(() => {
    if (!sourceFilter || sourceFilter === 'all') return filteredByStatus
    return filteredByStatus.filter((c) => c.source === sourceFilter)
  }, [filteredByStatus, sourceFilter])

  const filteredBySearch = useMemo(() => {
    if (!searchQuery.trim()) return filteredByStatusAndSource
    const q = searchQuery.trim().toLowerCase()
    return filteredByStatusAndSource.filter((c) => {
      const statusLabel = getStatusLabel(c.status).toLowerCase()
      const searchable = [
        c.name,
        c.email,
        c.phone,
        c.address,
        c.province,
        c.municipality,
        c.barangay,
        c.purokOrStreet,
        c.source,
        statusLabel,
        c.notes,
        c.adminNotes,
        c.createdAt,
        c.updatedAt,
        c.lastActivity,
        c.lastContact,
        c.nextFollowUp,
        c.archivedAt,
        c.archiveReason,
        String(c.dealsCount ?? ''),
      ]
        .filter(Boolean)
        .join(' ')
        .toLowerCase()
      return searchable.includes(q)
    })
  }, [filteredByStatusAndSource, searchQuery])

  const sortedForDisplay = useMemo(() => {
    const list = [...filteredBySearch]
    /** Walang piniling column: pinakabagong client sa taas (createdAt desc). */
    if (!sortBy) {
      list.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      return list
    }
    const mult = sortDir === 'asc' ? 1 : -1
    list.sort((a, b) => {
      let cmp = 0
      switch (sortBy) {
        case 'name':
          cmp = a.name.localeCompare(b.name)
          break
        case 'email':
          cmp = a.email.localeCompare(b.email)
          break
        case 'phone':
          cmp = a.phone.localeCompare(b.phone)
          break
        case 'dealsCount':
          cmp = a.dealsCount - b.dealsCount
          break
        case 'lastActivity':
          cmp = a.lastActivity.localeCompare(b.lastActivity)
          break
        default:
          return 0
      }
      return mult * cmp
    })
    return list
  }, [filteredBySearch, sortBy, sortDir])

  const handleSort = (col: SortCol) => {
    if (sortBy === col) {
      setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'))
    } else {
      setSortBy(col)
      setSortDir('asc')
    }
  }

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const toggleSelectAll = () => {
    if (selectedIds.size === sortedForDisplay.length) setSelectedIds(new Set())
    else setSelectedIds(new Set(sortedForDisplay.map((c) => c.id)))
  }

  const bulkStatus = (status: ClientStatus) => {
    const next = saveClientStore((prev) =>
      prev.map((c) => (selectedIds.has(c.id) ? { ...c, status } : c))
    )
    setClients(next)
    setSelectedIds(new Set())
  }

  const bulkDelete = () => {
    const selectedList = sortedForDisplay.filter((c) => selectedIds.has(c.id))
    const prioritySelected = selectedList.filter((c) => c.isPriority)
    if (prioritySelected.length > 0) {
      Swal.fire({
        icon: 'warning',
        title: 'Cannot archive priority clients',
        text: `${prioritySelected.length} selected client(s) are marked as priority. Please deselect them first.`,
      })
      return
    }
    setShowBulkArchiveModal(true)
    setBulkArchiveReason('')
    setBulkArchiveError('')
  }

  const confirmBulkArchive = () => {
    const reason = bulkArchiveReason.trim()
    if (!reason) {
      setBulkArchiveError('Please provide a reason for archiving.')
      return
    }
    const toArchive = fetchClients().filter((c) => selectedIds.has(c.id))
    
    // Asynchronously call API for each
    Promise.all(toArchive.map(c => deleteClientFromApi(c.id)))
      .catch(err => console.error('Bulk archive failed:', err))

    const next = saveClientStore((prev) =>
      prev.filter((c) => !selectedIds.has(c.id))
    )
    setClients(next)
    setSelectedIds(new Set())
    setShowBulkArchiveModal(false)
    setBulkArchiveReason('')
    setBulkArchiveError('')
    logClientActivity({
      actor,
      action: 'archived',
      entityType: 'client',
      entityId: null,
      entityLabel: `${toArchive.length} client(s)`,
      details: `Archived clients ${toArchive.map((c) => c.name).join(', ')} ΓÇö Reason: ${reason}`,
    })
    Swal.fire({
      icon: 'success',
      title: 'Archived successfully',
      toast: true,
      position: 'top-end',
      showConfirmButton: false,
      timer: 3000,
      timerProgressBar: true,
    })
  }

  const exportCsv = () => {
    const headers = ['Name', 'Email', 'Phone', 'Source', 'Status', 'Deals', 'Last Activity']
    const rows = sortedForDisplay.map((c) =>
      [c.name, c.email, c.phone, c.source, c.status, c.dealsCount, c.lastActivity].join(',')
    )
    const csv = [headers.join(','), ...rows].join('\n')
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'clients.csv'
    a.click()
    URL.revokeObjectURL(url)
  }

  const exportSelectedCsv = () => {
    const list = sortedForDisplay.filter((c) => selectedIds.has(c.id))
    if (list.length === 0) return
    const headers = ['Name', 'Email', 'Phone', 'Source', 'Status', 'Deals', 'Last Activity']
    const rows = list.map((c) =>
      [c.name, c.email, c.phone, c.source, c.status, c.dealsCount, c.lastActivity].join(',')
    )
    const csv = [headers.join(','), ...rows].join('\n')
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'clients-selected.csv'
    a.click()
    URL.revokeObjectURL(url)
  }

  const openAdd = () => {
    setEditingClient(null)
    setShowForm(true)
  }

  const openEdit = (c: ClientRecord) => {
    setEditingClient(c)
    setShowForm(true)
  }

  const closeForm = () => {
    setShowForm(false)
    setEditingClient(null)
  }

  const deleteClient = (c: ClientRecord) => {
    if (c.isPriority) {
      Swal.fire({
        icon: 'warning',
        title: 'Cannot archive priority client',
        text: `${c.name} is marked as priority and cannot be archived.`,
      })
      return
    }
    setArchiveModalClient(c)
    setArchiveReason('')
    setArchiveError('')
  }

  const confirmArchive = () => {
    if (!archiveModalClient) return
    const reason = archiveReason.trim()
    if (!reason) {
      setArchiveError('Please provide a reason for archiving.')
      return
    }
    // Call API (asynchronous)
    deleteClientFromApi(archiveModalClient.id).catch(err => {
      console.error('Delete client failed:', err)
    })

    const next = saveClientStore((prev) =>
      prev.filter((x) => x.id !== archiveModalClient.id)
    )
    setClients(next)
    setArchiveModalClient(null)
    setArchiveReason('')
    setArchiveError('')
    logClientActivity({
      actor,
      action: 'archived',
      entityType: 'client',
      entityId: archiveModalClient.id,
      entityLabel: archiveModalClient.name,
      details: `Archived client ${archiveModalClient.name} ΓÇö Reason: ${reason}`,
    })
    Swal.fire({
      icon: 'success',
      title: 'Archived successfully',
      toast: true,
      position: 'top-end',
      showConfirmButton: false,
      timer: 3000,
      timerProgressBar: true,
    })
  }

  const togglePriority = (c: ClientRecord) => {
    const next = saveClientStore((prev) =>
      prev.map((x) =>
      x.id === c.id ? { ...x, isPriority: !(x.isPriority ?? false) } : x
      )
    )
    setClients(next)
  }

  const lastActivityIcon = (type?: LastActivityType) => {
    switch (type) {
      case 'Inquiry': return <HiOutlineChat />
      case 'Call': return <HiOutlinePhone />
      case 'Email': return <HiOutlineMail />
      case 'Meeting': return <HiOutlineCalendar />
      case 'Reservation': return <HiOutlineCash />
      case 'Note': return <HiOutlineClipboardList />
      default: return <HiOutlineClock />
    }
  }

  const allClients = fetchClients().filter((c) => !c.archived)
  const totalClients = allClients.length
  const newLeads = allClients.filter((c) => c.status === 'new').length
  const inPipeline = allClients.filter((c) => PIPELINE_STATUSES.includes(c.status)).length
  const closedCount = allClients.filter((c) => c.status === 'closed').length
  const facebookLeads = allClients.filter((c) => c.source === 'Facebook').length
  const websiteLeads = allClients.filter((c) => c.source === 'Website').length

  return (
    <div className="admin-clients">
      <header className="clients-header">
        <h1 className="admin-page-title">Clients Management</h1>
        <div className="clients-header-actions">
          <input
            type="search"
            className="admin-input clients-search"
            placeholder="Search clients..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            aria-label="Search clients"
          />
          <div className="add-client-dropdown" ref={addMenuRef}>
            <button
              type="button"
              className="btn btn-primary"
              onClick={() => setAddMenuOpen((o) => !o)}
              aria-expanded={addMenuOpen}
              aria-haspopup="true"
            >
              <HiOutlinePlus className="btn-icon" /> Add Client
              <HiOutlineChevronDown className="add-client-chevron" />
            </button>
            {addMenuOpen && (
              <div className="add-client-menu" role="menu">
                <button
                  type="button"
                  role="menuitem"
                  className="add-client-menu-item"
                  onClick={() => { setAddMenuOpen(false); openAdd(); }}
                >
                  Add client
                </button>
                <button
                  type="button"
                  role="menuitem"
                  className="add-client-menu-item"
                  onClick={() => { setAddMenuOpen(false); setShowBulkUpload(true); }}
                >
                  Bulk upload
                </button>
              </div>
            )}
          </div>
          <button type="button" className="btn btn-outline" onClick={exportCsv}>
            <HiOutlineDocumentDownload className="btn-icon" /> Export CSV
          </button>
        </div>
      </header>

      <section className="clients-mini-stats">
        <button
          type="button"
          className={`mini-stat-card mini-stat-card--clickable ${!statusFilter || statusFilter === 'all' ? 'mini-stat-card--active' : ''}`}
          onClick={() => {
            if (!statusFilter || statusFilter === 'all') setSourceFilter('')
            else setStatusFilter('')
          }}
          title={!statusFilter || statusFilter === 'all' ? 'Clear source filter' : 'Show all clients (any status)'}
        >
          <span className="mini-stat-value">{totalClients}</span>
          <span className="mini-stat-label">Total Clients</span>
        </button>
        <button
          type="button"
          className={`mini-stat-card mini-stat-card--clickable ${statusFilter === 'new' ? 'mini-stat-card--active' : ''}`}
          onClick={() => setStatusFilter(statusFilter === 'new' ? '' : 'new')}
          title={statusFilter === 'new' ? 'Clear status filter' : 'Filter by New leads'}
        >
          <span className="mini-stat-value">{newLeads}</span>
          <span className="mini-stat-label">New Leads</span>
        </button>
        <button
          type="button"
          className={`mini-stat-card mini-stat-card--clickable ${statusFilter === 'pipeline' ? 'mini-stat-card--active' : ''}`}
          onClick={() => setStatusFilter(statusFilter === 'pipeline' ? '' : 'pipeline')}
          title={statusFilter === 'pipeline' ? 'Clear status filter' : 'Filter by In pipeline (contacted ΓåÆ reserved)'}
        >
          <span className="mini-stat-value">{inPipeline}</span>
          <span className="mini-stat-label">In Pipeline</span>
        </button>
        <button
          type="button"
          className={`mini-stat-card mini-stat-card--clickable ${statusFilter === 'closed' ? 'mini-stat-card--active' : ''}`}
          onClick={() => setStatusFilter(statusFilter === 'closed' ? '' : 'closed')}
          title={statusFilter === 'closed' ? 'Clear status filter' : 'Filter by Closed'}
        >
          <span className="mini-stat-value">{closedCount}</span>
          <span className="mini-stat-label">Closed</span>
        </button>
        <button
          type="button"
          className={`mini-stat-card mini-stat-card--clickable ${sourceFilter === 'Facebook' ? 'mini-stat-card--active' : ''}`}
          onClick={() => setSourceFilter(sourceFilter === 'Facebook' ? '' : 'Facebook')}
          title={sourceFilter === 'Facebook' ? 'Clear filter' : 'Filter by Facebook leads'}
        >
          <span className="mini-stat-value">{facebookLeads}</span>
          <span className="mini-stat-label">Facebook Leads</span>
        </button>
        <button
          type="button"
          className={`mini-stat-card mini-stat-card--clickable ${sourceFilter === 'Website' ? 'mini-stat-card--active' : ''}`}
          onClick={() => setSourceFilter(sourceFilter === 'Website' ? '' : 'Website')}
          title={sourceFilter === 'Website' ? 'Clear filter' : 'Filter by Website leads'}
        >
          <span className="mini-stat-value">{websiteLeads}</span>
          <span className="mini-stat-label">Website Leads</span>
        </button>
      </section>

      {selectedIds.size > 0 && (
        <div className="clients-bulk-bar" role="toolbar" aria-label="Bulk actions">
          <span className="bulk-bar-count">{selectedIds.size} selected</span>
          <span className="bulk-bar-sep" aria-hidden="true">|</span>
          <div className="bulk-bar-actions">
            <label htmlFor="bulk-status-select" className="bulk-bar-action-label">Change Status</label>
            <select
              id="bulk-status-select"
              className="bulk-bar-select admin-input"
              value={bulkStatusSelectValue}
              onChange={(e) => {
                const v = e.target.value as ClientStatus
                if (!v) return
                const label = getStatusLabel(v)
                Swal.fire({
                  icon: 'question',
                  title: 'Change status?',
                  html: `Change status to <strong>${label}</strong> for <strong>${selectedIds.size}</strong> selected client(s)?`,
                  showCancelButton: true,
                  confirmButtonText: 'Yes, change status',
                  cancelButtonText: 'Cancel',
                }).then((result) => {
                  if (result.isConfirmed) bulkStatus(v)
                  setBulkStatusSelectValue('')
                })
              }}
            >
              <option value="">Choose...</option>
              {STATUSES.map((s) => (
                <option key={s} value={s}>{getStatusLabel(s)}</option>
              ))}
            </select>
          </div>
          <span className="bulk-bar-sep" aria-hidden="true">|</span>
          <button type="button" className="btn btn-sm btn-outline bulk-bar-btn" onClick={exportSelectedCsv}>
            Export
          </button>
          <span className="bulk-bar-sep" aria-hidden="true">|</span>
          <button type="button" className="btn btn-sm btn-outline bulk-bar-btn bulk-bar-btn--archive" onClick={bulkDelete}>
            Archive
          </button>
        </div>
      )}

      <div className="admin-table-wrap clients-table-wrap">
        <table className="admin-table clients-table">
          <thead>
            <tr>
              <th className="col-checkbox">
                <input
                  type="checkbox"
                  checked={sortedForDisplay.length > 0 && selectedIds.size === sortedForDisplay.length}
                  onChange={toggleSelectAll}
                  aria-label="Select all"
                />
              </th>
              <th className={`th-filter th-sortable ${sortBy === 'name' ? 'th--sorted' : ''}`}>
                <button type="button" className="th-sort-btn" onClick={() => handleSort('name')} aria-label="Sort by name">
                  <span className="th-label">Name</span>
                  <span className="th-sort-icon">
                    {sortBy === 'name' ? (sortDir === 'asc' ? <HiOutlineChevronUp /> : <HiOutlineChevronDown />) : <><HiOutlineChevronUp /><HiOutlineChevronDown /></>}
                  </span>
                </button>
              </th>
              <th className={`th-filter th-sortable ${sortBy === 'email' ? 'th--sorted' : ''}`}>
                <button type="button" className="th-sort-btn" onClick={() => handleSort('email')} aria-label="Sort by email">
                  <span className="th-label">Email</span>
                  <span className="th-sort-icon">
                    {sortBy === 'email' ? (sortDir === 'asc' ? <HiOutlineChevronUp /> : <HiOutlineChevronDown />) : <><HiOutlineChevronUp /><HiOutlineChevronDown /></>}
                  </span>
                </button>
              </th>
              <th className={`th-filter th-sortable ${sortBy === 'phone' ? 'th--sorted' : ''}`}>
                <button type="button" className="th-sort-btn" onClick={() => handleSort('phone')} aria-label="Sort by phone">
                  <span className="th-label">Phone</span>
                  <span className="th-sort-icon">
                    {sortBy === 'phone' ? (sortDir === 'asc' ? <HiOutlineChevronUp /> : <HiOutlineChevronDown />) : <><HiOutlineChevronUp /><HiOutlineChevronDown /></>}
                  </span>
                </button>
              </th>
              <th className="th-filter col-source">
                <div className="th-status-wrap" ref={sourceDropdownRef}>
                  <button type="button" className="th-label-btn" onClick={() => setSourceDropdownOpen((o) => !o)} aria-label="Filter by source" aria-expanded={sourceDropdownOpen}>
                    <span className="th-label">Source</span>
                  </button>
                  <button
                    type="button"
                    className={`th-dropdown-trigger ${sourceDropdownOpen ? 'th-dropdown-trigger--open' : ''}`}
                    onClick={() => setSourceDropdownOpen((o) => !o)}
                    aria-label="Filter by source"
                    aria-expanded={sourceDropdownOpen}
                  >
                    <span className="th-dropdown-trigger-icon">
                      <HiOutlineMenu />
                      <HiOutlineChevronDown />
                    </span>
                  </button>
                  {sourceDropdownOpen && (
                    <div className="th-dropdown-menu" role="menu">
                      <button type="button" role="menuitem" className={`th-dropdown-item ${!sourceFilter || sourceFilter === 'all' ? 'th-dropdown-item--active' : ''}`} onClick={() => { setSourceFilter(''); setSourceDropdownOpen(false); }}>
                        All
                      </button>
                      {SOURCES.map((s) => (
                        <button key={s} type="button" role="menuitem" className={`th-dropdown-item ${sourceFilter === s ? 'th-dropdown-item--active' : ''}`} onClick={() => { setSourceFilter(s); setSourceDropdownOpen(false); }}>
                          {s}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </th>
              <th className="th-filter col-status">
                <div className="th-status-wrap" ref={statusDropdownRef}>
                  <button type="button" className="th-label-btn" onClick={() => setStatusDropdownOpen((o) => !o)} aria-label="Filter by status" aria-expanded={statusDropdownOpen}>
                    <span className="th-label">Status</span>
                  </button>
                  <button
                    type="button"
                    className={`th-dropdown-trigger ${statusDropdownOpen ? 'th-dropdown-trigger--open' : ''}`}
                    onClick={() => setStatusDropdownOpen((o) => !o)}
                    aria-label="Filter by status"
                    aria-expanded={statusDropdownOpen}
                  >
                    <span className="th-dropdown-trigger-icon">
                      <HiOutlineMenu />
                      <HiOutlineChevronDown />
                    </span>
                  </button>
                  {statusDropdownOpen && (
                    <div className="th-dropdown-menu" role="menu">
                      <button type="button" role="menuitem" className={`th-dropdown-item ${!statusFilter || statusFilter === 'all' ? 'th-dropdown-item--active' : ''}`} onClick={() => { setStatusFilter(''); setStatusDropdownOpen(false); }}>
                        All
                      </button>
                      <button
                        type="button"
                        role="menuitem"
                        className={`th-dropdown-item ${statusFilter === 'pipeline' ? 'th-dropdown-item--active' : ''}`}
                        onClick={() => {
                          setStatusFilter('pipeline')
                          setStatusDropdownOpen(false)
                        }}
                      >
                        In pipeline
                      </button>
                      {STATUSES.map((s) => (
                        <button key={s} type="button" role="menuitem" className={`th-dropdown-item ${statusFilter === s ? 'th-dropdown-item--active' : ''}`} onClick={() => { setStatusFilter(s); setStatusDropdownOpen(false); }}>
                          {getStatusLabel(s)}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </th>
              <th className={`th-filter th-sortable ${sortBy === 'dealsCount' ? 'th--sorted' : ''}`}>
                <button type="button" className="th-sort-btn" onClick={() => handleSort('dealsCount')} aria-label="Sort by deals">
                  <span className="th-label">Deals</span>
                  <span className="th-sort-icon">
                    {sortBy === 'dealsCount' ? (sortDir === 'asc' ? <HiOutlineChevronUp /> : <HiOutlineChevronDown />) : <><HiOutlineChevronUp /><HiOutlineChevronDown /></>}
                  </span>
                </button>
              </th>
              <th className={`th-filter th-sortable ${sortBy === 'lastActivity' ? 'th--sorted' : ''}`}>
                <button type="button" className="th-sort-btn" onClick={() => handleSort('lastActivity')} aria-label="Sort by last activity">
                  <span className="th-label">Last Activity</span>
                  <span className="th-sort-icon">
                    {sortBy === 'lastActivity' ? (sortDir === 'asc' ? <HiOutlineChevronUp /> : <HiOutlineChevronDown />) : <><HiOutlineChevronUp /><HiOutlineChevronDown /></>}
                  </span>
                </button>
              </th>
              <th className="col-priority">Mark Priority</th>
              <th className="col-actions">Actions</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td colSpan={10} className="admin-empty-cell">
                  Loading clients...
                </td>
              </tr>
            ) : sortedForDisplay.length === 0 ? (
              <tr>
                <td colSpan={10} className="admin-empty-cell">
                  No clients match your search.
                </td>
              </tr>
            ) : (
              sortedForDisplay.map((c) => (
              <tr key={c.id}>
                <td className="col-checkbox">
                  <input
                    type="checkbox"
                    checked={selectedIds.has(c.id)}
                    onChange={() => toggleSelect(c.id)}
                    aria-label={`Select ${c.name}`}
                  />
                </td>
                <td>{c.name}</td>
                <td>{c.email}</td>
                <td>{c.phone}</td>
                <td className="col-source">{c.source}</td>
                <td className="col-status">
                  <StatusBadge
                    className={`admin-badge admin-badge--${c.status}`}
                    title={getStatusDescription(c.status)}
                  >
                    {getStatusLabel(c.status)}
                  </StatusBadge>
                </td>
                <td className="col-deals">
                  <Link
                    to={`/admin/deals${c.dealsCount ? `?clientId=${c.id}` : ''}`}
                    className="deals-view-btn"
                    title={c.dealsCount ? `View deals for ${c.name}` : 'No deals'}
                  >
                    {c.dealsCount}
                  </Link>
                </td>
                <td className="col-last-activity">
                  <span className="last-activity-cell" title={c.lastActivityType ? `${c.lastActivity} (${c.lastActivityType})` : c.lastActivity}>
                    <span className="last-activity-icon">{lastActivityIcon(c.lastActivityType)}</span>
                    <span className="last-activity-text">{c.lastActivity}</span>
                  </span>
                </td>
                <td className="col-priority">
                  <button
                    type="button"
                    className={`priority-indicator ${c.isPriority ? 'priority-indicator--on' : ''}`}
                    onClick={() => togglePriority(c)}
                    title={c.isPriority ? 'Remove priority' : 'Mark as priority'}
                    aria-label={c.isPriority ? 'Remove priority' : 'Mark as priority'}
                  >
                    <span className="priority-dot" />
                  </button>
                </td>
                <td className="col-actions">
                  <Link
                    to={`/admin/deals?clientId=${c.id}&createDeal=1`}
                    className="btn-icon-btn"
                    data-tooltip="Create deal ΓÇö opens Deals with this client selected so you can start a new transaction."
                    title="Create deal ΓÇö new transaction for this client"
                    aria-label="Create a new deal for this client"
                  >
                    <HiOutlineCash />
                  </Link>
                  <Link
                    to={`/admin/clients/${c.id}`}
                    className="btn-icon-btn"
                    data-tooltip="View client ΓÇö open full profile (contacts, deals, activity, notes)."
                    title="View client ΓÇö full profile and history"
                    aria-label="View client profile"
                  >
                    <HiOutlineEye />
                  </Link>
                  <button
                    type="button"
                    className="btn-icon-btn"
                    data-tooltip="Edit client ΓÇö update name, contact, source, and notes in the side panel."
                    title="Edit client ΓÇö details and notes"
                    aria-label="Edit this client"
                    onClick={() => openEdit(c)}
                  >
                    <HiOutlinePencil />
                  </button>
                  <a
                    href={`mailto:${c.email}`}
                    className="btn-icon-btn"
                    data-tooltip={`Email client ΓÇö opens your mail app to ${c.email}.`}
                    title={`Send email to ${c.email}`}
                    aria-label={`Send email to ${c.name}`}
                  >
                    <HiOutlineChat />
                  </a>
                  <button
                    type="button"
                    className="btn-icon-btn btn-icon-btn--archive"
                    data-tooltip={
                      c.isPriority
                        ? 'Archive unavailable ΓÇö remove priority first; priority clients stay active.'
                        : 'Archive client ΓÇö hides from the main list; related records stay linked.'
                    }
                    title={
                      c.isPriority
                        ? 'Cannot archive while marked priority'
                        : 'Archive client ΓÇö soft-hide from list'
                    }
                    onClick={() => !c.isPriority && deleteClient(c)}
                    disabled={!!c.isPriority}
                    aria-label={
                      c.isPriority
                        ? 'Priority clients cannot be archived. Remove priority first.'
                        : 'Archive client'
                    }
                  >
                    <HiOutlineArchive />
                  </button>
                </td>
              </tr>
            ))
            )}
          </tbody>
        </table>
      </div>

      {showBulkUpload && (
        <BulkUploadModal
          onClose={() => setShowBulkUpload(false)}
          onUploaded={(newList) => {
            saveClientStore(() => newList)
            setClients(newList)
            setShowBulkUpload(false)
          }}
        />
      )}

      {archiveModalClient && (
        <div className="admin-modal-overlay" onClick={() => setArchiveModalClient(null)} role="dialog" aria-modal="true" aria-labelledby="archive-modal-title">
          <div className="admin-modal archive-modal" onClick={(e) => e.stopPropagation()}>
            <div className="admin-modal-header">
              <h2 id="archive-modal-title">Archive client</h2>
              <button type="button" className="admin-modal-close" onClick={() => setArchiveModalClient(null)} aria-label="Close">&times;</button>
            </div>
            <div className="admin-modal-body">
              <div className="archive-warning">
                <p className="archive-warning-title">ΓÜá∩╕Å Confirmation</p>
                <p>You are about to archive <strong>{archiveModalClient.name}</strong>.</p>
              </div>
              <div className="admin-form-row">
                <label htmlFor="archive-reason">Reason for archiving <span className="required">*</span></label>
                <textarea
                  id="archive-reason"
                  className="admin-input"
                  value={archiveReason}
                  onChange={(e) => { setArchiveReason(e.target.value); setArchiveError(''); }}
                  placeholder="e.g. Client requested removal, duplicate, moved to competitor"
                  rows={3}
                  required
                />
              </div>
              {archiveError && <p className="form-error">{archiveError}</p>}
              <div className="archive-actions">
                <button type="button" className="btn btn-primary" onClick={confirmArchive}>
                  Archive client
                </button>
                <button type="button" className="btn btn-outline" onClick={() => setArchiveModalClient(null)}>Cancel</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showBulkArchiveModal && (
        <div className="admin-modal-overlay" onClick={() => setShowBulkArchiveModal(false)} role="dialog" aria-modal="true" aria-labelledby="bulk-archive-modal-title">
          <div className="admin-modal archive-modal" onClick={(e) => e.stopPropagation()}>
            <div className="admin-modal-header">
              <h2 id="bulk-archive-modal-title">Archive selected clients</h2>
              <button type="button" className="admin-modal-close" onClick={() => setShowBulkArchiveModal(false)} aria-label="Close">&times;</button>
            </div>
            <div className="admin-modal-body">
              <div className="archive-warning">
                <p className="archive-warning-title">ΓÜá∩╕Å Confirmation</p>
                <p>You are about to archive <strong>{selectedIds.size} client{selectedIds.size !== 1 ? 's' : ''}</strong>.</p>
              </div>
              <div className="admin-form-row">
                <label htmlFor="bulk-archive-reason">Reason for archiving <span className="required">*</span></label>
                <textarea
                  id="bulk-archive-reason"
                  className="admin-input"
                  value={bulkArchiveReason}
                  onChange={(e) => { setBulkArchiveReason(e.target.value); setBulkArchiveError(''); }}
                  placeholder="e.g. Batch cleanup, campaign ended"
                  rows={3}
                  required
                />
              </div>
              {bulkArchiveError && <p className="form-error">{bulkArchiveError}</p>}
              <div className="archive-actions">
                <button type="button" className="btn btn-primary" onClick={confirmBulkArchive}>
                  Archive {selectedIds.size} client{selectedIds.size !== 1 ? 's' : ''}
                </button>
                <button type="button" className="btn btn-outline" onClick={() => setShowBulkArchiveModal(false)}>Cancel</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showForm && (
        <ClientFormSidebar
          key={editingClient?.id ?? 'new'}
          client={editingClient}
          onClose={closeForm}
          onSave={(client) => {
            const wasEdit = !!editingClient
            if (wasEdit) {
              const next = saveClientStore((prev) =>
                prev.map((c) => (c.id === client.id ? client : c))
              )
              setClients(next)
              logClientActivity({
                actor,
                action: 'updated',
                entityType: 'client',
                entityId: client.id,
                entityLabel: client.name,
                details: 'Client details updated',
              })
            } else {
              const next = saveClientStore((prev) => [...prev, client])
              setClients(next)
              logClientActivity({
                actor,
                action: 'created',
                entityType: 'client',
                entityId: client.id,
                entityLabel: client.name,
                details: 'New client added',
              })
            }
            closeForm()
            // Defer toast until after sidebar unmounts so SweetAlert2 isnΓÇÖt blocked by overlay/focus
            window.setTimeout(() => {
              void Swal.fire({
                icon: 'success',
                title: wasEdit ? 'Client updated' : 'Client added',
                toast: true,
                position: 'top-end',
                showConfirmButton: false,
                timer: 2500,
                timerProgressBar: true,
              })
            }, 0)
          }}
        />
      )}
    </div>
  )
}

function ClientFormSidebar({
  client,
  onClose,
  onSave,
}: {
  client: ClientRecord | null
  onClose: () => void
  onSave: (c: ClientRecord) => void
}) {
  const isEdit = !!client
  const [name, setName] = useState(client?.name ?? '')
  const [email, setEmail] = useState(client?.email ?? '')
  const [phone, setPhone] = useState(client?.phone ?? '')
  const [municipality, setMunicipality] = useState(client?.municipality ?? '')
  const [barangay, setBarangay] = useState(client?.barangay ?? '')
  const [purokOrStreet, setPurokOrStreet] = useState(client?.purokOrStreet ?? '')
  const [source, setSource] = useState<ClientSource>(client?.source ?? 'Website')
  const [status, setStatus] = useState<ClientStatus>(client?.status ?? 'new')
  const [notes, setNotes] = useState(client?.notes ?? '')
  const [password, setPassword] = useState('')
  const [saving, setSaving] = useState(false)

  const barangayOptions = useMemo(() => {
    const base = getBarangaysForMunicipality(municipality)
    if (barangay && !base.includes(barangay)) {
      return [barangay, ...base]
    }
    return [...base]
  }, [municipality, barangay])

  const validate = (): boolean => {
    if (!name.trim()) {
      Swal.fire({ icon: 'warning', title: 'Name Required', text: 'Full name is required.' })
      return false
    }
    const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!emailRe.test(email)) {
      Swal.fire({ icon: 'error', title: 'Invalid Email', text: 'Please enter a valid email address.' })
      return false
    }
    const allClients = getClientStore()
    const emailDuplicate = allClients.find((c) => c.email.toLowerCase() === email.toLowerCase() && c.id !== client?.id)
    if (emailDuplicate) {
      Swal.fire({ 
        icon: 'error', 
        title: 'Email Already Used', 
        html: `The email <strong>${email}</strong> is already used by <strong>${emailDuplicate.name}</strong>.` 
      })
      return false
    }
    const phoneDigits = phone.replace(/\s/g, '')
    const phoneDuplicate = allClients.find((c) => c.phone.replace(/\s/g, '') === phoneDigits && c.id !== client?.id)
    if (phoneDuplicate) {
      Swal.fire({ 
        icon: 'error', 
        title: 'Phone Already Used', 
        html: `The phone number <strong>${phone}</strong> is already used by <strong>${phoneDuplicate.name}</strong>.` 
      })
      return false
    }
    if (!isValidPhMobile09(phoneDigits)) {
      Swal.fire({ icon: 'warning', title: 'Invalid Phone', text: 'Phone must be 11 digits starting with 09.' })
      return false
    }
    if (!municipality.trim()) {
      Swal.fire({ icon: 'warning', title: 'Location Required', text: 'Municipality / city is required.' })
      return false
    }
    if (!barangay.trim()) {
      Swal.fire({ icon: 'warning', title: 'Location Required', text: 'Barangay is required.' })
      return false
    }
    return true
  }

  const handleSave = async () => {
    if (!validate()) return
    const now = new Date().toISOString().slice(0, 10)
    const mun = municipality.trim()
    const brgy = barangay.trim()
    const purok = purokOrStreet.trim()
    const phoneDigits = phone.replace(/\s/g, '')
    const addressLine = formatBulacanAddressLine({
      purokOrStreet: purok || undefined,
      barangay: brgy,
      municipality: mun,
      province: BULACAN_PROVINCE,
    })

    const draft: ClientRecord =
      isEdit && client
        ? {
            ...client,
            name: name.trim(),
            email: email.trim().toLowerCase(),
            phone: phoneDigits,
            province: BULACAN_PROVINCE,
            municipality: mun,
            barangay: brgy,
            purokOrStreet: purok || undefined,
            address: addressLine,
            source,
            status,
            notes: notes.trim(),
            updatedAt: now,
          }
        : {
            id: 'c' + Date.now(),
            name: name.trim(),
            email: email.trim().toLowerCase(),
            phone: phoneDigits,
            province: BULACAN_PROVINCE,
            municipality: mun,
            barangay: brgy,
            purokOrStreet: purok || undefined,
            address: addressLine,
            source,
            status,
            notes: notes.trim(),
            createdAt: now,
            updatedAt: now,
            dealsCount: 0,
            lastActivity: now,
            adminNotes: '',
          }

    setSaving(true)
    try {
      const saved = await persistClientToApi(draft)
      onSave(saved)
    } catch (e) {
      Swal.fire({ 
        icon: 'error', 
        title: 'Save Failed', 
        text: e instanceof Error ? e.message : 'Failed to save client.' 
      })
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="client-sidebar-overlay" onClick={onClose} role="presentation">
      <div className="client-sidebar" onClick={(e) => e.stopPropagation()} role="dialog" aria-label={isEdit ? 'Edit Client' : 'Add Client'}>
        <div className="client-sidebar-header">
          <h2>{isEdit ? 'Edit Client' : 'Add Client'}</h2>
          <button type="button" className="client-sidebar-close" onClick={onClose} aria-label="Close">├ù</button>
        </div>
        <div className="client-sidebar-body">
          <div className="admin-form-row">
            <label>Full Name *</label>
            <input
              className="admin-input"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Full name"
            />
          </div>
          <div className="admin-form-row">
            <label>Email *</label>
            <input
              type="email"
              className="admin-input"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="email@example.com"
            />
          </div>
          <div className="admin-form-row">
            <label>Phone *</label>
            <input
              type="tel"
              className="admin-input"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              placeholder="09171234567 (11 digits, starts with 09)"
            />
          </div>
          <div className="admin-form-row">
            <label>Province / city *</label>
            <input className="admin-input" value={BULACAN_PROVINCE} readOnly disabled />
          </div>
          <div className="admin-form-row">
            <label>Municipality / city *</label>
            <select
              className="admin-input"
              value={municipality}
              onChange={(e) => {
                const m = e.target.value
                setMunicipality(m)
                const nextOpts = getBarangaysForMunicipality(m)
                setBarangay((prev) => (prev && nextOpts.includes(prev) ? prev : ''))
              }}
              required
            >
              <option value="">Select municipalityΓÇª</option>
              {BULACAN_MUNICIPALITIES.map((m) => (
                <option key={m} value={m}>
                  {m}
                </option>
              ))}
            </select>
          </div>
          <div className="admin-form-row">
            <label>Barangay *</label>
            <select
              className="admin-input"
              value={barangay}
              onChange={(e) => setBarangay(e.target.value)}
              disabled={!municipality}
              required
            >
              <option value="">{municipality ? 'Select barangayΓÇª' : 'Select municipality firstΓÇª'}</option>
              {barangayOptions.map((b) => (
                <option key={b} value={b}>
                  {b}
                </option>
              ))}
            </select>
          </div>
          <div className="admin-form-row">
            <label>Purok / street</label>
            <input
              className="admin-input"
              value={purokOrStreet}
              onChange={(e) => setPurokOrStreet(e.target.value)}
              placeholder="Optional (e.g. Purok 1, Rizal St.)"
            />
          </div>
          <div className="admin-form-row">
            <label>Source</label>
            <select className="admin-input" value={source} onChange={(e) => setSource(e.target.value as ClientSource)}>
              {SOURCES.map((s) => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          </div>
          <div className="admin-form-row">
            <label>Status</label>
            <select className="admin-input" value={status} onChange={(e) => setStatus(e.target.value as ClientStatus)}>
              {STATUSES.map((s) => (
                <option key={s} value={s}>{getStatusLabel(s)}</option>
              ))}
            </select>
          </div>
          <div className="admin-form-row">
            <label>Notes</label>
            <textarea
              className="admin-input"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Notes"
              rows={2}
            />
          </div>
          {!isEdit && (
            <div className="admin-form-row">
              <label>Password (if login enabled)</label>
              <input
                type="password"
                className="admin-input"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Optional"
              />
            </div>
          )}
        </div>
        <FormActions
          primaryLabel={saving ? 'SavingΓÇª' : 'Save'}
          onPrimary={() => void handleSave()}
          onCancel={onClose}
          primaryDisabled={saving}
        />
      </div>
    </div>
  )
}

function BulkUploadModal({
  onClose,
  onUploaded,
}: {
  onClose: () => void
  onUploaded: (newList: ClientRecord[]) => void
}) {
  const [file, setFile] = useState<File | null>(null)
  const [error, setError] = useState('')
  const [uploading, setUploading] = useState(false)

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0]
    setFile(f ?? null)
    setError('')
  }

  const handleSubmit = () => {
    if (!file) {
      setError('Choose a CSV file.')
      return
    }
    setUploading(true)
    setError('')
    const reader = new FileReader()
    reader.onload = () => {
      try {
        const text = String(reader.result)
        const lines = text.split(/\r?\n/).filter((line) => line.trim())
        if (lines.length < 2) {
          setError('CSV must have a header row and at least one data row.')
          setUploading(false)
          return
        }
        const headerLine = lines[0]
        const headers = headerLine.split(',').map((h) => h.trim().toLowerCase())
        const nameIdx = headers.indexOf('name') >= 0 ? headers.indexOf('name') : 0
        const emailIdx = headers.indexOf('email') >= 0 ? headers.indexOf('email') : 1
        const phoneIdx = headers.indexOf('phone') >= 0 ? headers.indexOf('phone') : 2
        const sourceIdx = headers.indexOf('source') >= 0 ? headers.indexOf('source') : 3
        const statusIdx = headers.indexOf('status') >= 0 ? headers.indexOf('status') : 4
        const today = new Date().toISOString().slice(0, 10)
        const existing = getClientStore()
        const newClients: ClientRecord[] = []
        for (let i = 1; i < lines.length; i++) {
          const cols = lines[i].split(',').map((c) => c.trim().replace(/^"|"$/g, ''))
          const name = cols[nameIdx] ?? ''
          const email = cols[emailIdx] ?? ''
          const phone = cols[phoneIdx] ?? ''
          if (!name || !email) continue
          const source = SOURCES.includes((cols[sourceIdx] ?? '') as ClientSource) ? (cols[sourceIdx] as ClientSource) : 'Website'
          const status = STATUSES.includes((cols[statusIdx] ?? '') as ClientStatus) ? (cols[statusIdx] as ClientStatus) : 'new'
          const dealsCount = parseInt(cols[5] ?? '0', 10) || 0
          const lastActivity = cols[6] ?? today
          newClients.push({
            id: `bulk-${Date.now()}-${i}`,
            name,
            email,
            phone,
            province: BULACAN_PROVINCE,
            municipality: 'Malolos',
            barangay: 'POBLACION',
            address: formatBulacanAddressLine({
              barangay: 'POBLACION',
              municipality: 'Malolos',
              province: BULACAN_PROVINCE,
            }),
            source,
            status,
            notes: '',
            createdAt: today,
            updatedAt: today,
            dealsCount,
            lastActivity,
            adminNotes: '',
          })
        }
        if (newClients.length === 0) {
          setError('No valid rows found. CSV needs at least Name and Email.')
          setUploading(false)
          return
        }
        onUploaded([...existing, ...newClients])
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to parse CSV.')
      }
      setUploading(false)
    }
    reader.onerror = () => {
      setError('Failed to read file.')
      setUploading(false)
    }
    reader.readAsText(file, 'UTF-8')
  }

  return (
    <div className="admin-modal-overlay" onClick={onClose} role="dialog" aria-modal="true" aria-labelledby="bulk-upload-title">
      <div className="admin-modal bulk-upload-modal" onClick={(e) => e.stopPropagation()}>
        <div className="admin-modal-header">
          <h2 id="bulk-upload-title">Bulk upload clients</h2>
          <button type="button" className="admin-modal-close" onClick={onClose} aria-label="Close">&times;</button>
        </div>
        <div className="admin-modal-body">
          <p className="bulk-upload-hint">Upload a CSV with columns: Name, Email, Phone (optional: Source, Status, Deals, Last Activity).</p>
          <div className="file-input-wrap">
            <span className="file-input-btn">
              <span className="file-input-icon">≡ƒôä</span>
              Choose CSV fileΓÇª
            </span>
            <input
              type="file"
              accept=".csv"
              className="file-input-hidden"
              onChange={handleFileChange}
              aria-label="Choose CSV file"
            />
          </div>
          {error && <p className="form-error">{error}</p>}
          <div className="admin-form-actions" style={{ marginTop: '1rem' }}>
            <button type="button" className="btn btn-primary" onClick={handleSubmit} disabled={uploading}>
              {uploading ? 'Uploading...' : 'Upload'}
            </button>
            <button type="button" className="btn btn-outline" onClick={onClose}>Cancel</button>
          </div>
        </div>
      </div>
    </div>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { HiOutlineCash, HiOutlinePhone, HiOutlinePlus, HiOutlineTrash, HiOutlineUser } from 'react-icons/hi'
import Swal from 'sweetalert2'
import { SIMULATION_STORAGE_KEY } from '../../data/simulationSnapshot'
import { formatPeso } from '../../utils/mortgageUtils'
import {
  budgetRangeLabel,
  buyingTimelineLabel,
  employmentStatusLabel,
  financingMethodLabel,
} from '../../data/leadQualification'
import type { InquiryRecord, InquiryStatus, LeadPriority } from '../../data/mockAdmin'
import { convertLeadToClientAndPersist, fetchClients } from '../../services/clientsService'
import {
  fetchInquiries,
  markInquiryAsContacted,
  saveInquiryStore,
  updateInquiryInApi,
  deleteInquiryFromApi,
} from '../../services/inquiriesService'
import { computeNextFollowUpDateFromTimeline, getFollowUpUiKind } from '../../utils/inquiryFollowUp'
import { fetchProperties } from '../../services/propertiesService'
import { logActivity } from '../../data/activityLog'
import PageHeader from '../../components/PageHeader'
import DataTable from '../../components/DataTable'
import StatusBadge from '../../components/StatusBadge'
import FormActions from '../../components/FormActions'
import './admin-common.css'
import './Inquiries.css'

export default function AdminInquiries() {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const actor = 'Admin'
  const INQUIRY_STATUSES: InquiryStatus[] = ['new', 'contacted', 'qualified', 'converted', 'lost']
  const PRIORITY_OPTIONS: LeadPriority[] = ['low', 'medium', 'high']
  const SOURCE_OPTIONS = ['facebook', 'website', 'walk-in', 'referral'] as const
  type LeadSource = (typeof SOURCE_OPTIONS)[number]
  const INQUIRY_STATUS_LABELS: Record<InquiryStatus, string> = {
    new: 'Pending',
    contacted: 'Contacted',
    qualified: 'Qualified',
    converted: 'Converted',
    lost: 'Lost',
  }

  const [inquiries, setInquiries] = useState<InquiryRecord[]>(() => fetchInquiries())
  const [searchQuery, setSearchQuery] = useState('')
  const [showAddLead, setShowAddLead] = useState(false)
  const [loading, setLoading] = useState(true)
  const [archiveModalInquiry, setArchiveModalInquiry] = useState<InquiryRecord | null>(null)
  const [archiveReason, setArchiveReason] = useState('')
  const [archiveError, setArchiveError] = useState('')
  const properties = fetchProperties().filter((p) => !p.archived)

  useEffect(() => {
    setLoading(false)
  }, [])

  /** Re-load from shared store (same tab after submit, or other tab via localStorage). */
  useEffect(() => {
    const syncFromStore = () => {
      setInquiries(fetchInquiries())
    }
    syncFromStore()
    const onFocus = () => syncFromStore()
    const onStorage = (e: StorageEvent) => {
      if (e.key === SIMULATION_STORAGE_KEY) syncFromStore()
    }
    window.addEventListener('focus', onFocus)
    window.addEventListener('storage', onStorage)
    return () => {
      window.removeEventListener('focus', onFocus)
      window.removeEventListener('storage', onStorage)
    }
  }, [])

  const updateInquiries = (updater: (prev: InquiryRecord[]) => InquiryRecord[]) => {
    setInquiries((prev) => {
      const next = updater(prev)
      saveInquiryStore(() => next)
      return next
    })
  }

  const normalizeSource = (raw: string): LeadSource => {
    const s = String(raw).toLowerCase()
    if (s.includes('facebook')) return 'facebook'
    if (s.includes('walk')) return 'walk-in'
    if (s.includes('referral')) return 'referral'
    if (s.includes('website') || s.includes('property page')) return 'website'
    return 'website'
  }

  const getLeadSource = (i: InquiryRecord): LeadSource | null => {
    const auto = i.source_auto ?? null
    const manual = i.source_manual ?? null
    if (auto) return normalizeSource(auto)
    if (manual) return normalizeSource(manual)
    return null
  }

  const getInquirySourceDisplay = (i: InquiryRecord) => {
    const source = getLeadSource(i)
    if (source) return source
    return 'ΓÇö'
  }

  /** All table-visible (and id) fields for global search */
  const inquirySearchHaystack = (i: InquiryRecord): string => {
    const parts: string[] = [
      i.id,
      i.name,
      i.email,
      i.phone,
      i.propertyId ?? '',
      i.propertyTitle,
      i.message,
      i.notes ?? '',
      INQUIRY_STATUS_LABELS[i.status],
      i.status,
      getInquirySourceDisplay(i),
      i.source_auto ?? '',
      i.source_manual ?? '',
      i.utm_campaign ?? '',
      i.utm_medium ?? '',
      budgetRangeLabel(i.budgetRange),
      buyingTimelineLabel(i.buyingTimeline),
      financingMethodLabel(i.financingMethod),
      employmentStatusLabel(i.employmentStatus),
      i.nextFollowUpAt ?? '',
      i.lastContactedAt ?? '',
      i.lostReason ?? '',
      i.linkedClientId ?? '',
      new Date(i.createdAt).toLocaleDateString(),
      String(i.createdAt),
      i.highBuyingIntent ? 'high buying intent' : '',
    ]
    if (i.estimatedMonthly != null && Number.isFinite(i.estimatedMonthly)) {
      parts.push(String(i.estimatedMonthly), formatPeso(Math.round(i.estimatedMonthly)))
    }
    if (i.downpayment) parts.push(i.downpayment)
    if (i.loanTerm != null) parts.push(String(i.loanTerm), `${i.loanTerm} yr`)
    if (i.interestRate != null) parts.push(String(i.interestRate), `${i.interestRate}%`)
    if (i.downpaymentPercent != null) parts.push(String(i.downpaymentPercent))
    return parts.join(' ').toLowerCase()
  }

  const handleConvertToClient = async (lead: InquiryRecord) => {
    if (lead.status === 'converted') return

    let clientId: string | null = null
    let created = false
    try {
      const converted = await convertLeadToClientAndPersist(lead)
      clientId = converted.clientId
      created = converted.created
    } catch (err) {
      Swal.fire({
        icon: 'error',
        title: 'Could not convert lead',
        text: err instanceof Error ? err.message : 'Failed to save client to the server.',
      })
      return
    }
    const updatedRow: InquiryRecord = {
      ...lead,
      status: 'converted',
      linkedClientId: clientId,
    }
    updateInquiries((prev) =>
      prev.map((row) =>
        row.id === lead.id ? { ...row, status: 'converted', linkedClientId: clientId } : row
      )
    )

    try {
      await updateInquiryInApi(updatedRow)
    } catch {
      /* local store already updated; DB sync failed ΓÇö user can retry status change */
    }

    logActivity({
      actor,
      action: 'status_changed',
      entityType: 'inquiry',
      entityId: lead.id,
      entityLabel: lead.name,
      details: `Status changed: ${INQUIRY_STATUS_LABELS[lead.status]} -> ${INQUIRY_STATUS_LABELS.converted}`,
    })
    logActivity({
      actor,
      action: 'created',
      entityType: 'client',
      entityId: clientId ?? '',
      entityLabel: lead.name,
      details: created
        ? `Converted lead to new client: ${lead.name} (${lead.email})`
        : `Matched existing client by email and updated from lead: ${lead.name} (${lead.email})`,
    })
    Swal.fire({
      icon: 'success',
      title: 'Lead converted to client',
      toast: true,
      position: 'top-end',
      showConfirmButton: false,
      timer: 2500,
      timerProgressBar: true,
    })

    if (clientId) {
      navigate(`/admin/clients/${clientId}?fromLead=1`)
    }
  }

  const handleCreateDealFromLead = async (lead: InquiryRecord) => {
    let clientId: string | null = null
    try {
      const converted = await convertLeadToClientAndPersist(lead)
      clientId = converted.clientId
    } catch (err) {
      Swal.fire({
        icon: 'error',
        title: 'Could not create client for this deal',
        text: err instanceof Error ? err.message : 'Failed to save client to the server.',
      })
      return
    }

    const synced: InquiryRecord = { ...lead, status: 'converted', linkedClientId: clientId }
    updateInquiries((prev) =>
      prev.map((row) =>
        row.id === lead.id ? { ...row, status: 'converted', linkedClientId: clientId } : row
      )
    )
    try {
      await updateInquiryInApi(synced)
    } catch {
      /* local CRM updated; DB sync optional */
    }

    const client = fetchClients().find((c) => c.id === clientId)
    const params = new URLSearchParams({
      createDeal: '1',
      clientId: clientId ?? '',
      clientName: client?.name ?? lead.name,
      leadOriginId: lead.id,
    })
    if (lead.propertyId) params.set('propertyId', lead.propertyId)
    if (lead.propertyTitle) params.set('propertyTitle', lead.propertyTitle)
    navigate(`/admin/deals?${params.toString()}`)
    Swal.fire({
      icon: 'info',
      title: 'Create deal',
      text: 'Choose property and confirm price on the Deals page.',
      toast: true,
      position: 'top-end',
      showConfirmButton: false,
      timer: 2200,
    })
  }

  const handleMarkAsContacted = async (lead: InquiryRecord) => {
    markInquiryAsContacted(lead.id)
    const updated = fetchInquiries().find((x) => x.id === lead.id)
    setInquiries(fetchInquiries())
    if (!updated) return
    try {
      await updateInquiryInApi(updated)
      logActivity({
        actor,
        action: 'updated',
        entityType: 'inquiry',
        entityId: lead.id,
        entityLabel: lead.name,
        details: 'Marked as contacted; next follow-up set to +2 days',
      })
      Swal.fire({
        icon: 'success',
        title: 'Follow-up updated',
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 2000,
        timerProgressBar: true,
      })
    } catch {
      Swal.fire({
        icon: 'error',
        title: 'Could not save to server',
        text: 'Follow-up was updated locally. Sign in again or check your connection.',
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 4000,
      })
    }
  }

  const handleArchiveInquiry = (lead: InquiryRecord) => {
    setArchiveModalInquiry(lead)
    setArchiveReason('')
    setArchiveError('')
  }

  const confirmArchiveInquiry = async () => {
    if (!archiveModalInquiry) return
    const reason = archiveReason.trim()
    if (!reason) {
      setArchiveError('Please provide a reason for archiving.')
      return
    }

    try {
      await deleteInquiryFromApi(archiveModalInquiry.id)
      updateInquiries((prev) => prev.filter((row) => row.id !== archiveModalInquiry.id))
      
      logActivity({
        actor,
        action: 'archived',
        entityType: 'inquiry',
        entityId: archiveModalInquiry.id,
        entityLabel: archiveModalInquiry.name,
        details: `Archived inquiry from ${archiveModalInquiry.name} ΓÇö Reason: ${reason}`,
      })

      Swal.fire({
        icon: 'success',
        title: 'Inquiry archived',
        toast: true,
        position: 'top-end',
        showConfirmButton: false,
        timer: 2000,
        timerProgressBar: true,
      })
      setArchiveModalInquiry(null)
      setArchiveReason('')
      setArchiveError('')
    } catch (err) {
      Swal.fire({
        icon: 'error',
        title: 'Archive failed',
        text: err instanceof Error ? err.message : 'Could not archive inquiry.',
      })
    }
  }

  const handleAddLead = (payload: {
    name: string
    email: string
    phone: string
    propertyId: string | null
    propertyTitle: string
    message: string
    notes: string
    source: LeadSource
    priority: LeadPriority
    lastContactedAt: string | null
    nextFollowUpAt: string | null
  }) => {
    const nowIso = new Date().toISOString()
    const nextLead: InquiryRecord = {
      id: `inq-${Date.now()}`,
      name: payload.name.trim(),
      email: payload.email.trim(),
      phone: payload.phone.trim(),
      propertyId: payload.propertyId,
      propertyTitle: payload.propertyTitle.trim(),
      message: payload.message.trim(),
      notes: payload.notes.trim(),
      source_auto: payload.source,
      source_manual: payload.source,
      status: 'new',
      priority: payload.priority,
      createdAt: nowIso,
      lastContactedAt: payload.lastContactedAt,
      nextFollowUpAt:
        payload.nextFollowUpAt?.trim() ||
        computeNextFollowUpDateFromTimeline(new Date(), null),
      lostReason: null,
      linkedClientId: null,
      estimatedMonthly: null,
      downpayment: null,
      loanTerm: null,
      interestRate: null,
      downpaymentPercent: null,
      highBuyingIntent: false,
      budgetRange: null,
      buyingTimeline: null,
      financingMethod: null,
      employmentStatus: null,
    }

    updateInquiries((prev) => [nextLead, ...prev])
    setShowAddLead(false)
    Swal.fire({
      icon: 'success',
      title: 'Lead added',
      toast: true,
      position: 'top-end',
      showConfirmButton: false,
      timer: 2200,
      timerProgressBar: true,
    })
  }

  const filtered = useMemo(() => {
    let list = [...inquiries]

    if (searchQuery.trim()) {
      const q = searchQuery.trim().toLowerCase()
      list = list.filter((i) => inquirySearchHaystack(i).includes(q))
    }

    list.sort((a, b) => {
      const diff = new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      if (diff !== 0) return diff
      return String(b.id).localeCompare(String(a.id))
    })

    return list
  }, [inquiries, searchQuery])

  const focusInquiryId = searchParams.get('focus')
  useEffect(() => {
    if (!focusInquiryId || loading) return
    const timer = window.setTimeout(() => {
      const safeId = focusInquiryId.replace(/"/g, '')
      const row = document.querySelector(`[data-inquiry-row="${safeId}"]`)
      if (row instanceof HTMLElement) {
        row.scrollIntoView({ behavior: 'smooth', block: 'center' })
        row.classList.add('admin-inquiry-row--flash')
        window.setTimeout(() => row.classList.remove('admin-inquiry-row--flash'), 2400)
      }
    }, 200)
    return () => clearTimeout(timer)
  }, [focusInquiryId, loading, inquiries])

  return (
    <div className="admin-inquiries">
      <PageHeader
        title="Lead Management"
        subtitle="FB leads, website leads, walk-ins, referrals ΓÇö track and convert."
        toolbar={
          <>
            <input
              type="search"
              className="admin-input admin-inquiries-search"
              placeholder="Search name, contact, property, message, status, source, budget, ΓÇª"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              aria-label="Search all lead fields"
            />
            <button type="button" className="btn btn-primary" onClick={() => setShowAddLead(true)}>
              <HiOutlinePlus className="btn-icon" /> Add Lead
            </button>
          </>
        }
      />
      <div className="admin-inquiries-legends admin-inquiries-legends--row">
        <div className="admin-inquiries-legend" role="note">
          <span className="admin-inquiry-intent-dot admin-inquiry-intent-dot--legend" aria-hidden />
          <span className="admin-inquiries-legend-text">high buying customer</span>
        </div>
        <div className="admin-inquiries-legend admin-inquiries-legend--followup-rows" role="note">
          <span className="admin-inquiries-legend-text admin-inquiries-legend-text--compact">
            <span className="admin-inquiries-legend-item">
              <span className="admin-inquiries-legend-swatch admin-inquiries-legend-swatch--overdue" aria-hidden />
              Overdue
            </span>
            <span className="admin-inquiries-legend-item">
              <span className="admin-inquiries-legend-swatch admin-inquiries-legend-swatch--today" aria-hidden />
              Due today
            </span>
            <span className="admin-inquiries-legend-item">
              <span className="admin-inquiries-legend-swatch admin-inquiries-legend-swatch--upcoming" aria-hidden />
              Upcoming
            </span>
          </span>
        </div>
      </div>
      <DataTable wrapperClassName="admin-inquiries-table-wrap" tableClassName="inquiries-table">
          <thead>
            <tr>
            <th className="th-plain">
              <span className="th-label">Name</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Contact</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Property</span>
            </th>
            <th className="th-plain">
              <span className="th-label">Message</span>
            </th>
            <th className="th-plain col-qualify">
              <span className="th-label">Budget</span>
            </th>
            <th className="th-plain col-qualify">
              <span className="th-label">Timeline</span>
            </th>
            <th className="th-plain col-qualify">
              <span className="th-label">Financing</span>
            </th>
            <th className="th-plain col-payment-est">
              <span className="th-label">Payment est.</span>
            </th>
            <th className="th-plain col-source">
              <span className="th-label">Source</span>
            </th>
            <th className="th-plain col-status">
              <span className="th-label">Status</span>
            </th>
            <th className="th-plain col-inquiry-date">
              <span className="th-label">Date</span>
            </th>
            <th className="col-actions">Actions</th>
            </tr>
          </thead>
          <tbody>
          {loading ? (
            <tr>
              <td colSpan={12} className="admin-empty-cell">
                Loading leads...
              </td>
            </tr>
          ) : filtered.length === 0 ? (
            <tr>
              <td colSpan={12} className="admin-empty-cell">
                No leads found.
                </td>
              </tr>
            ) : (
              filtered.map((i) => {
                const followKind = getFollowUpUiKind(i)
                return (
                <tr
                  key={i.id}
                  data-inquiry-row={i.id}
                  className={followKind ? `admin-inquiry-row--followup-${followKind}` : undefined}
                >
                <td>
                  <div className="admin-inquiry-name-cell">
                    {i.highBuyingIntent ? (
                      <span
                        className="admin-inquiry-intent-dot"
                        title="High buying customer"
                        aria-label="High buying customer"
                      />
                    ) : null}
                    <span>{i.name}</span>
                  </div>
                </td>
                <td>
                  <div className="admin-inquiry-contact">
                    <a href={`mailto:${i.email}`}>{i.email}</a>
                    <small>{i.phone}</small>
                  </div>
                  </td>
                  <td>{i.propertyTitle}</td>
                  <td className="admin-inquiry-message">{i.message}</td>
                <td className="admin-inquiry-qualify">{budgetRangeLabel(i.budgetRange)}</td>
                <td className="admin-inquiry-qualify">{buyingTimelineLabel(i.buyingTimeline)}</td>
                <td className="admin-inquiry-qualify">{financingMethodLabel(i.financingMethod)}</td>
                <td className="admin-inquiry-payment-est">
                  {i.estimatedMonthly != null && Number.isFinite(i.estimatedMonthly) ? (
                    <div className="admin-inquiry-payment-est-inner">
                      <span className="admin-inquiry-payment-est-monthly">
                        {formatPeso(Math.round(i.estimatedMonthly))}/mo
                      </span>
                      {i.downpayment ? (
                        <span className="admin-inquiry-payment-est-line">DP: {i.downpayment}</span>
                      ) : null}
                      {i.loanTerm != null ? (
                        <span className="admin-inquiry-payment-est-line">
                          {i.loanTerm} yr
                          {i.interestRate != null ? ` @ ${i.interestRate}%` : ''}
                        </span>
                      ) : null}
                    </div>
                  ) : (
                    <span className="admin-inquiry-payment-est-empty">ΓÇö</span>
                  )}
                </td>
                  <td className="admin-inquiry-source">
                  <StatusBadge className={`admin-badge admin-badge--source-${getInquirySourceDisplay(i).replace(/[^a-z-]/g, '')}`}>
                    {getInquirySourceDisplay(i)}
                  </StatusBadge>
                </td>
                <td className="col-status">
                  <select
                    className={`admin-input admin-inquiry-status-select admin-inquiry-status-select--${i.status}`}
                    value={i.status}
                    onChange={async (e) => {
                      const next = e.target.value as InquiryStatus
                      if (next === i.status) return
                      const prevStatus = i.status
                      const updatedRow: InquiryRecord = { ...i, status: next }
                      updateInquiries((prev) => prev.map((row) => (row.id === i.id ? updatedRow : row)))
                      try {
                        const saved = await updateInquiryInApi(updatedRow)
                        updateInquiries((prev) => prev.map((row) => (row.id === i.id ? saved : row)))
                        logActivity({
                          actor,
                          action: 'status_changed',
                          entityType: 'inquiry',
                          entityId: i.id,
                          entityLabel: i.name,
                          details: `Status changed: ${INQUIRY_STATUS_LABELS[prevStatus]} -> ${INQUIRY_STATUS_LABELS[next]}`,
                        })
                        Swal.fire({
                          icon: 'success',
                          title: 'Status updated',
                          toast: true,
                          position: 'top-end',
                          showConfirmButton: false,
                          timer: 2000,
                          timerProgressBar: true,
                        })
                      } catch (err) {
                        updateInquiries((prev) => prev.map((row) => (row.id === i.id ? i : row)))
                        Swal.fire({
                          icon: 'error',
                          title: 'Could not save status',
                          text: err instanceof Error ? err.message : 'Failed to update inquiry on server.',
                          toast: true,
                          position: 'top-end',
                          showConfirmButton: false,
                          timer: 4000,
                        })
                      }
                    }}
                  >
                    {INQUIRY_STATUSES.map((s) => (
                      <option key={s} value={s}>
                        {INQUIRY_STATUS_LABELS[s]}
                      </option>
                    ))}
                  </select>
                  </td>
                  <td className="admin-inquiry-date-cell">{new Date(i.createdAt).toLocaleDateString()}</td>
                <td className="col-actions col-actions--inquiry">
                  <button
                    type="button"
                    className="btn-icon-btn btn-icon-btn--contacted"
                    onClick={() => handleMarkAsContacted(i)}
                    disabled={i.status === 'converted' || i.status === 'lost'}
                    data-tooltip="Mark as contacted ΓÇö saves last contacted as now and sets the next follow-up to 2 days from today."
                    title="Mark as contacted ΓÇö last contact = now; next follow-up in 2 days"
                    aria-label="Mark as contacted: record contact time and schedule next follow-up in two days"
                  >
                    <HiOutlinePhone />
                  </button>
                  <button
                    type="button"
                    className="btn-icon-btn"
                    onClick={() => handleConvertToClient(i)}
                    disabled={i.status === 'converted'}
                    data-tooltip="Convert to client ΓÇö creates or links a client record and opens their profile."
                    title="Convert to client ΓÇö create/link client and open profile"
                    aria-label="Convert this lead to a client"
                  >
                    <HiOutlineUser />
                  </button>
                  <button
                    type="button"
                    className="btn-icon-btn"
                    onClick={() => handleCreateDealFromLead(i)}
                    disabled={i.status === 'lost'}
                    data-tooltip="Create deal ΓÇö opens Deals with this client (and property when set) to start a transaction."
                    title="Create deal ΓÇö start a deal for this client"
                    aria-label="Create a new deal from this lead"
                  >
                    <HiOutlineCash />
                  </button>
                  <button
                    type="button"
                    className="btn-icon-btn btn-icon-btn--danger"
                    onClick={() => handleArchiveInquiry(i)}
                    data-tooltip="Archive inquiry ΓÇö moves this inquiry to archives (soft delete)."
                    title="Archive inquiry"
                    aria-label="Archive lead"
                  >
                    <HiOutlineTrash />
                  </button>
                  </td>
                </tr>
                )
              })
            )}
          </tbody>
      </DataTable>
      {showAddLead && (
        <LeadFormSidebar
