const API_KEY = import.meta.env.VITE_GEMINI_API_KEY || ''

export async function transcribeAudio(audioBlob: Blob): Promise<string> {
  const mimeType = audioBlob.type || 'audio/webm'
  const buffer = await audioBlob.arrayBuffer()
  const base64 = btoa(String.fromCharCode(...new Uint8Array(buffer)))

  const body = {
    contents: [
      {
        parts: [
          {
            text: 'Transcribe this audio recording exactly as spoken. Return only the raw transcription text ΓÇö no labels, no formatting, no extra commentary.',
          },
          { inline_data: { mime_type: mimeType, data: base64 } },
        ],
      },
    ],
  }

  const res = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${API_KEY}`,
    { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
  )

  if (!res.ok) throw new Error(`Transcription failed: ${await res.text()}`)
  const data = await res.json()
  return data?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() ?? ''
}

